```C++
#include <iostream>
#include <string>
#include <regex>

std::string markdown_to_html(const std::string& markdown) {
    std::string html;
    std::regex e("\\n+");

    for (std::string::const_iterator it = markdown.begin(); it!= markdown.end(); ++it) {
        if (*it == '#') {
            html += "<h1>";
        } else if (*it == '*' || *it == '-') {
            html += "<ul>";
            html += "<li>";
        } else if (*it == '1' || *it == '2' || *it == '3') {
            html += "<ol>";
            html += "<li>";
            html += "1. ";
        } else if (*it == 'a' || *it == 'b' || *it == 'i' || *it == 'u') {
            html += "<i>";
        } else if (*it == '[' || *it == ']') {
            html += "<a href=\"http://example.com\">";
        } else if (*it == '\\n' || *it == '\r' || *it == '\t') {
            html += "<br>";
        } else {
            html += *it;
        }
    }

    return html;
}
```

This function uses a regular expression to replace consecutive line breaks with `<br>` tags, and to replace asterisks and hyphens with unordered lists. It also replaces the first character with `<h1>` for headings, and `<i>` for italic text. Finally, it wraps links in `<a>` tags. Note that this is a very simple converter and does not handle all possible markdown syntax.

